    # Initialize best node choice
    best_score = float('inf')
    best_node = None

    # Consider current density of trucks around each customer
    density_scores = np.zeros(len(unvisited_customers))
    for i, customer_pos in enumerate(unvisited_customers):
        for truck_pos in all_truck_pos:
            density_scores[i] += calculate_distance(truck_pos, customer_pos)
