import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def logistic_cost_penalty(arrival, start, end):
        if arrival < start:
            return 50 * (1 / (1 + np.exp(-(start - arrival) / 10))) - 25
        elif arrival > end:
            return 50 * (1 / (1 + np.exp(-(arrival - end) / 10))) - 25
        else:
            return 0

    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    if len(unvisited_customers) == 0:
        return None

    # Updating scores mechanism by considering other trucks' positions to avoid redundancy
    scores = []
    for i, customer in enumerate(unvisited_customers):
        travel_time = distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        start, end = time_windows[i]

        # Penalty for overlapping potential visits from other trucks
        overlap_penalty = sum(distance(truck_pos, customer) < distance(cur_truck_pos, customer) for truck_pos in all_truck_pos) * 10

        penalty = logistic_cost_penalty(arrival_time, start, end)
        score = travel_time + penalty + overlap_penalty
        scores.append((score, i))

    best_score, best_node = min(scores, key=lambda x: x[0])

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.sqrt((p1[0] - p2[0])**2 + (p1[1] - p2[1])**2)

    num_customers = len(unvisited_customers)
    if num_customers == 0:
        return None

    min_time_to_reach = np.inf
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        if arrival_time > end_window:
            # Late arrival, consider the penalty cost
            penalty_time = arrival_time - end_window
        else:
            penalty_time = max(0, start_window - arrival_time)  # Waiting time if early

        total_effective_time = arrival_time + penalty_time

        # Evaluate the best option based on minimizing the time when the truck can start serving this customer or wait until service starts
        if total_effective_time < min_time_to_reach:
            min_time_to_reach = total_effective_time
            best_node = i

    return best_node
